raw_output:
{
  "experiment_plan": {
    "what_to_compare": "ヨーロッパ系集団におけるMI症例と対照で、(1) HDL-C上昇を予測する単一SNP（LIPG Asn396Ser）キャリア vs 非キャリア、(2) HDL-C遺伝スコア高値 vs 低値、(3) LDL-C遺伝スコアを正のコントロールとして比較する。さらに、HDL-C関連IVごとにMI効果の一貫性を比較し、LDL-C調整前後の差も比較する。",
    "what_to_measure": "各IVについて、HDL-Cへの関連強度、MIのオッズ比、LDL-Cとの関連、他の脂質指標（特にトリグリセリド、non-HDL-C）との関連、IV間の効果異質性、用量反応（HDL-C上昇量とMIリスク低下の対応）、および可能ならHDL機能指標（コレステロール排出能、抗炎症性）を測定する。",
    "procedure": "1) 事前にHDL-C関連IVを単一SNPと多SNPスコアに分ける。2) 各IVがHDL-Cを上げることを確認する。3) 各IVとMIの関連を推定する。4) LDL-Cを含む脂質共変量で調整した解析を行う。5) IVごとのMI効果の方向・大きさの一貫性を評価する。6) HDL-C上昇量とMI効果の用量反応を評価する。7) LDL-Cスコアを正のコントロールとして、既知の方向の関連が再現されるか確認する。8) 可能ならHDL機能指標を層別化して、量的HDL-C上昇と機能改善の寄与を分離する。9) 事前に定めた判定規則に従い、各仮説を独立に評価する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "関連性仮定: 各遺伝的操作変数はHDL-Cを十分に予測し、弱いIVではないこと。",
        "if_violated": "HDL-Cへの関連が弱く、MR推定が不安定で因果判定不能となる。"
      },
      {
        "id": "IA2",
        "description": "独立性仮定: 遺伝的操作変数は、集団構造・年齢・性別・主要な交絡因子と独立であること。",
        "if_violated": "遺伝子頻度差や選択バイアスにより、MIとの関連が交絡される。"
      },
      {
        "id": "IA3",
        "description": "排除制約仮定: HDL-C関連IVは、HDL-C以外の経路でMIに影響しないこと。",
        "if_violated": "水平的多面発現により、観察されたMI関連がHDL-C因果効果ではなくなる。"
      },
      {
        "id": "IA4",
        "description": "単調性仮定: IVによるHDL-C上昇の方向が集団内で概ね一貫していること。",
        "if_violated": "反対方向の個体が多く、平均効果の解釈が困難になる。"
      },
      {
        "id": "IA5",
        "description": "測定仮定: HDL-C、LDL-C、MI診断が誤分類なく、少なくとも非差別的に測定されること。",
        "if_violated": "測定誤差により効果推定が減衰または歪む。"
      },
      {
        "id": "IA6",
        "description": "SNP間独立性仮定: 多SNPスコアを用いる場合、主要SNP群は十分に独立でLDの影響が最小であること。",
        "if_violated": "スコアが同一シグナルを重複計上し、効果推定が過大または不安定になる。"
      },
      {
        "id": "IA7",
        "description": "機能指標仮定: HDL機能指標を用いる場合、それがHDLの生物学的機能を妥当に反映すること。",
        "if_violated": "H4の判定が量的HDL-Cと機能の区別に失敗する。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "単一SNPと多SNPスコアの両方でHDL-C上昇がMIリスク低下と同方向に関連し、かつLDL-C調整後も効果が残存し、IV間の異質性が小さい。",
        "reject_if": "HDL-C上昇を予測するIVが、十分な検出力の下でMI低下と一貫して関連せず、またはLDL-C調整後に効果が消失する。",
        "hold_if": "HDL-C関連IVはMIと関連するが、IV間で効果が不一致、またはLDL-C調整後の残存効果が不明確で、因果性を確定できない。"
      },
      {
        "id": "H2",
        "accept_if": "HDL-C関連IV間でMI効果が不一致で、特定SNP群のみがMIと関連し、HDL-C上昇量との用量反応が弱いか消失し、さらにHDL-C以外の経路との関連が示唆される。",
        "reject_if": "複数の独立IV設計で同方向の保護効果が再現され、かつHDL-C以外の経路による説明が支持されない。",
        "hold_if": "IV間の効果異質性はあるが、HDL-C以外の経路との関連証拠が不十分で、多面発現の有無を断定できない。"
      },
      {
        "id": "H3",
        "accept_if": "HDL-C単独のIVではMI低下が弱く、LDL-C低下を伴う遺伝スコアでのみ保護効果が現れ、LDL-C調整でHDL-C関連効果が消失または大きく減弱する。",
        "reject_if": "LDL-Cや他の脂質指標を調整しても、HDL-C上昇に対応するMI低下が独立に残る。",
        "hold_if": "HDL-C関連IVのMI効果があるが、LDL-C媒介か独立効果かを統計的に分離できない。"
      },
      {
        "id": "H4",
        "accept_if": "HDL-C量を上げるIVでも、HDL機能を改善しない変異ではMI保護が見られず、機能改善を伴う変異でのみ保護効果が観察される。",
        "reject_if": "HDL-C量の遺伝的上昇が、機能指標を問わず一貫してMI低下と関連する。",
        "hold_if": "HDL機能指標の測定が不十分、または量と機能の寄与が分離できず、文脈依存性を判定できない。"
      }
    ],
    "analysis_forks": [
      "単一SNP MRと多SNP MRを別々に推定し、結果が一致するかを比較する。",
      "LDL-C調整なし解析とLDL-C調整あり解析を分けて、H1/H3の識別に使う。",
      "HDL-C関連IVごとのleave-one-out解析を行い、特定SNP依存の結果かを確認する。",
      "IV間異質性が高い場合は、固定効果MRとランダム効果MRを分岐して解釈する。",
      "HDL機能指標が利用可能なら、HDL-C量のみの効果と機能指標を伴う効果を層別化する。",
      "LDL-C正のコントロールが期待どおりMIと関連しない場合は、データ品質または解析設定を再点検する。",
      "多面発現の疑いが強い場合は、HDL-C関連IVを機能的に注釈し、脂質以外の経路との関連を追加検証する。",
      "用量反応が弱い場合は、HDL-C上昇量の連続尺度解析とカテゴリ解析を分けて評価する。"
    ]
  }
}
